<?php
namespace App\Services\Notifications;
use App\Jobs\Notifications\SendNotificationChannelJob; use App\Models\Notifications\{AppNotification,NotificationCampaign,NotificationPreference,NotificationSuppressionLog}; use App\Models\User; use Illuminate\Support\Collection;
class NotificationService { public function sendToUser(User $user,string $type,string $title,string $body,array $data=[],array $options=[]):?AppNotification{ $actor=$options['actor_user_id']??null; if($actor && $actor===$user->id && empty($options['send_to_actor'])) return null; $campaign=$options['campaign']??null; $dedupe=$options['dedupe_key']??($data['dedupe_key']??null); if(!$this->shouldSendToUser($user,$type,$dedupe,$campaign)) return null; $n=$this->createInAppNotification($user,$type,$title,$body,$data,$options); $channels=explode(',', str_replace('both','push,email',$n->channel)); foreach($channels as $ch){$ch=trim($ch); if(in_array($ch,['push','email'],true)) SendNotificationChannelJob::dispatch($n->id,$ch);} $log=NotificationSuppressionLog::firstOrNew(['user_id'=>$user->id,'type'=>$type,'dedupe_key'=>$dedupe]); $log->campaign_id=$campaign?->id; $log->last_sent_at=now(); $log->send_count=((int) $log->send_count ?: 0)+1; $log->save(); return $n;} public function sendToUsers(Collection|array $users,string $type,string $title,string $body,array $data=[],array $options=[]):Collection{return collect($users)->map(fn($u)=>$this->sendToUser($u,$type,$title,$body,$data,$options))->filter()->values();} public function createInAppNotification(User $user,string $type,string $title,string $body,array $data=[],array $options=[]):AppNotification{ $screen=$options['screen']??($data['screen']??null); $referenceId=$options['reference_id']??($data['reference_id']??null); $payload=array_merge($data,['screen'=>$screen,'reference_id'=>$referenceId]); return AppNotification::create(['user_id'=>$user->id,'campaign_id'=>$options['campaign']?->id??($options['campaign_id']??null),'type'=>$type,'category'=>$options['category']??null,'title'=>$title,'body'=>$body,'channel'=>$options['channel']??'push','priority'=>$options['priority']??'medium','reference_type'=>$options['reference_type']??($data['reference_type']??null),'reference_id'=>$referenceId,'screen'=>$screen,'data'=>$payload,'dedupe_key'=>$options['dedupe_key']??($data['dedupe_key']??null),'status'=>'pending']);} public function sendPushNotification(AppNotification $n):void{SendNotificationChannelJob::dispatch($n->id,'push');} public function sendEmailNotification(AppNotification $n):void{SendNotificationChannelJob::dispatch($n->id,'email');} public function renderTemplate(string $template,array $placeholders):string{foreach($placeholders as $k=>$v){$template=str_replace(['{{'.$k.'}}','{'.$k.'}'],(string)$v,$template);} return $template;} public function shouldSendToUser(User $user,string $type,?string $dedupeKey,?NotificationCampaign $campaign):bool{ if($campaign && !$campaign->is_active)return false; $p=NotificationPreference::firstOrCreate(['user_id'=>$user->id]); if(!$p->push_enabled && !$p->email_enabled)return false; if($campaign && !$p->campaign_enabled)return false; if($type==='chat_message' && !$p->chat_enabled)return false; if($dedupeKey && AppNotification::where('user_id',$user->id)->where('dedupe_key',$dedupeKey)->exists())return false; $priority=$campaign?->priority ?? 'medium'; if($priority==='urgent')return true; $limit=['high'=>5,'medium'=>3,'low'=>1][$priority]??3; return AppNotification::where('user_id',$user->id)->where('priority',$priority)->whereDate('created_at',today())->count() < ($campaign?->daily_limit ?? $limit); } public function markAsRead(User $user,string $notificationId):AppNotification{ $n=AppNotification::where('user_id',$user->id)->findOrFail($notificationId); if(!$n->read_at)$n->update(['read_at'=>now()]); return $n;} public function markAllAsRead(User $user):int{return AppNotification::where('user_id',$user->id)->whereNull('read_at')->update(['read_at'=>now()]);} public function recordClick(User $user,string $notificationId):AppNotification{ $n=AppNotification::where('user_id',$user->id)->findOrFail($notificationId); $n->update(['clicked_at'=>now(),'read_at'=>$n->read_at??now()]); return $n;}}
